const body = $json.body || $json;
const decision = body.decision;
const approvalId = body.approval_id || body.approvalId;
const reasoning = (body.reasoning || '').trim();
const modificationNotes = (body.modification_notes || body.modificationNotes || '').trim();

if (!approvalId || !decision) {
  throw new Error('approval_id and decision are required');
}
if (!['approved', 'denied', 'modified'].includes(decision)) {
  throw new Error('decision must be approved|denied|modified');
}
if (decision === 'denied' && !reasoning) {
  throw new Error('reasoning is required when decision=denied');
}

return [{
  json: {
    approval_id: approvalId,
    decision,
    reasoning: reasoning || null,
    modification_notes: modificationNotes || null,
    decided_by_email: body.decided_by_email || body.decider_email || null
  }
}];

const row = Array.isArray($json) ? $json[0] : $json;
const input = $('Validate Payload').item.json;
if (!row || !row.id) throw new Error('Approval not found');
if (row.status !== 'pending') throw new Error('Approval already processed');

return [{
  json: {
    ...input,
    approval: row
  }
}];

const user = Array.isArray($json) ? $json[0] : $json;
if (!user || !user.id) throw new Error('Decider user mapping missing in users table');
const context = $('Ensure Pending').item.json;

return [{
  json: {
    ...context,
    decided_by_user_id: user.id,
    decided_at: new Date().toISOString()
  }
}];

const updated = Array.isArray($json) ? $json[0] : $json;
if (!updated || !updated.id) throw new Error('Approval update conflict');
const context = $('Build Decision Update').item.json;
const approval = context.approval;

return [{
  json: {
    approval_id: updated.id,
    requesting_agent_id: approval.requesting_agent_id,
    action_proposed: approval.summary,
    action_pattern: approval.action_type + '_' + (approval.approval_trigger || 'none'),
    supporting_data: approval.supporting_data || null,
    confidence_level: approval.confidence || null,
    cross_department_impact: Array.isArray(approval.affected_departments) ? approval.affected_departments.join(',') : null,
    risk_assessment: approval.risk_level || null,
    decision: context.decision,
    reasoning: context.reasoning || null,
    modification_notes: context.modification_notes || null,
    decided_by: context.decided_by_user_id
  }
}];
